// hasPromotables returns true when at least one row is a successful
// SPRITE upload that hasn't already been promoted. Drives the bulk
// promote footer button. Tile sheets self-promote at slice time
// (autoSliceTileSheet); audio has no sprite. Sprite uploads are the
// only kind that benefits from a one-click "make these paintable"
// affordance after the fact.
func hasPromotables(items []AssetUploadItem) bool {
	for _, it := range items {
		if it.AssetID > 0 && it.Err == "" && !it.Promoted && it.Kind == "sprite" {
			return true
		}
	}
	return false
}

// promotableIDs returns a comma-joined string of asset ids ready to be
// promoted: successful sprites that aren't already promoted. Plain
// ASCII safe for an `ids=...` query param. Empty list returns "" so
// the resulting URL is harmless if it ever escapes hasPromotables's
// gate.
func promotableIDs(items []AssetUploadItem) string {
	out := ""
	for _, it := range items {
		if it.AssetID > 0 && it.Err == "" && !it.Promoted && it.Kind == "sprite" {
			if out != "" {
				out += ","
			}
			out += intToA(int(it.AssetID))
		}
	}
	return out
}

// uploadAddedCaption produces the per-row success caption. For tile
// sheets we surface the slice count so the designer can confirm at a
// glance that "tile sheet → N paintable cells" worked.
func uploadAddedCaption(it AssetUploadItem) string {
	if it.Kind == "tile" {
		switch {
		case it.TileEntityCount == 0:
			return "added as tile sheet"
		case it.TileEntityCount == 1:
			return "added as tile sheet · 1 paintable cell"
		default:
			return "added as tile sheet · " + intToA(it.TileEntityCount) + " paintable cells"
		}
	}
	if it.Kind == "sprite" && it.SpriteFrameCount > 1 {
		caption := "added as sprite sheet · " + intToA(it.SpriteFrameCount) + " frames"
		if it.SpriteAnimationCount > 0 {
			caption += " · " + intToA(it.SpriteAnimationCount) + " animations"
		}
		return caption
	}
	return "added as " + it.Kind
}

// uploadReusedCaption is the caption for a re-uploaded asset. Tile
// sheets still get the cell-count surfaced when re-slicing added
// cells (e.g. designer deleted some and wants them back).
func uploadReusedCaption(it AssetUploadItem) string {
	if it.Kind == "tile" && it.TileEntityCount > 0 {
		switch it.TileEntityCount {
		case 1:
			return "already in library · 1 new cell added"
		default:
			return "already in library · " + intToA(it.TileEntityCount) + " new cells added"
		}
	}
	if it.Kind == "sprite" && it.SpriteFrameCount > 1 {
		caption := "already in library · " + intToA(it.SpriteFrameCount) + " frames"
		if it.SpriteAnimationCount > 0 {
			caption += " · " + intToA(it.SpriteAnimationCount) + " animations"
		}
		return caption
	}
	return "already in library"
}

func uploadResultSeverity(reused bool) string {
	if reused {
		return "info"
	}
	return "success"
}

func multiUploadSeverity(ok, fail int) string {
	switch {
	case ok == 0 && fail > 0:
		return "error"
	case fail > 0:
		return "warn"
	default:
		return "success"
	}
}

func multiUploadHeadline(ok, fail int) string {
	switch {
	case ok == 0 && fail == 0:
		return "Nothing uploaded."
	case ok == 0:
		return pluralFiles(fail) + " failed."
	case fail == 0 && ok == 1:
		return "1 file added."
	case fail == 0:
		return pluralFiles(ok) + " added."
	default:
		return pluralFiles(ok) + " added, " + pluralFiles(fail) + " failed."
	}
}

func pluralFiles(n int) string {
	if n == 1 {
		return "1 file"
	}
	return intToA(n) + " files"
}

// intToA: tiny templ-safe integer-to-string. Same shape as formatIntPad
// from layout.templ, kept local so this template doesn't have to import
// strconv.
func intToA(n int) string {
	if n == 0 {
		return "0"
	}
	out := ""
	neg := n < 0
	if neg {
		n = -n
	}
	for n > 0 {
		out = string(rune('0'+byte(n%10))) + out
		n /= 10
	}
	if neg {
		out = "-" + out
	}
	return out
}

